insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'J''ai reconnu que c''était aujourd''hui à la nappe du dimanche.',$$Joyeuse fête. J''ai reconnu que c''était aujourd''hui à la nappe du dimanche.
Pas la nappe habituelle. L''autre. Celle du placard du haut. Celle qui sort quatre fois par an. Je l''ai vue sur la table ce matin et j''ai tout compris immédiatement. Ce signe textile. Ce signal que quelque chose d''important approche. J''ai ajusté mon programme de la journée en conséquence. Joyeuse fête, mon humain préféré, dont la nappe est mon calendrier.
Avec lecture du signal textile et adaptation logistique immédiate, — {prenom}, ton animal dont le nez et les yeux lisent les événements avant toi 🍽️$$,'humorous',true,false,'nameday','chat','from'),

(null,'J''ai observé ta façon de choisir ta tenue ce soir.',$$Pour ta fête j''ai observé ta façon de choisir ta tenue ce soir.
